body {
  font-family: "Inter", "Segoe UI", Arial, sans-serif;
  background: #f8f9fb;
  margin: 0;
}

.address-container {
  display: flex;
  gap: 40px;
  background: #fff;
  border-radius: 8px;
  padding: 20px 24px;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.06);
  animation: slideDown 0.5s ease;
}

.address-column {
  flex: 1;
}

.address-title {
  color: #002050;
  font-weight: 700;
  font-size: 15px;
  margin-bottom: 10px;
}

.address-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 12px;
  border-radius: 4px;
  animation: fadeIn 0.4s ease;
}

/* Alternate row background */
.address-row:nth-child(odd) {
  background: #ffffff; /* light gray */
}

.address-row:nth-child(even) {
  background: #f5f5f5; /* white */
}

.label {
  color: #222;
  font-weight: 500;
}

.value {
  font-weight: 700;
  color: #0a0a0a;
}

